import React, { useState } from "react";
import Marquee from "react-fast-marquee";
import img1 from "./images/01.png";
import img2 from "./images/02.png";
import img3 from "./images/03.png";
import "./App.css";

function MarqueeExample() {
  const [tooltipVisible, setTooltipVisible] = useState(false);
  const [tooltipX, setTooltipX] = useState(0);
  const [tooltipY, setTooltipY] = useState(0);

  function handleClick(imageIndex) {
    switch (imageIndex) {
      case 0:
        window.location.href = "page1.html";
        break;
      case 1:
        window.location.href = "page2.html";
        break;
      case 2:
        window.location.href = "page3.html";
        break;
      default:
        break;
    }
  }

  function handleMouseEnter(e) {
    const mouseX = e.clientX;
    const mouseY = e.clientY;
    setTooltipX(mouseX + 20);
    setTooltipY(mouseY);
    setTooltipVisible(true);
  }

  function handleMouseMove(e) {
    const mouseX = e.clientX;
    const mouseY = e.clientY;
    setTooltipX(mouseX + 20);
    setTooltipY(mouseY);
  }

  function handleMouseLeave() {
    setTooltipVisible(false);
  }

  // Get all the elements with class "marquee-item"
  const marqueeItems = document.querySelectorAll(".marquee-item");

  // Loop through each element and attach event listeners
  marqueeItems.forEach((item) => {
    // Get the tooltip element inside the current item
    const tooltip = item.querySelector(".tooltip");

    // Attach event listeners to show/hide the tooltip
    item.addEventListener("mouseenter", (e) => {
      // Position the tooltip inside the current item
      tooltip.style.top = `${e.offsetY}px`;
      tooltip.style.left = `${e.offsetX}px`;
      tooltip.style.display = "block";
    });
    item.addEventListener("mousemove", (e) => {
      // Position the tooltip inside the current item
      tooltip.style.top = `${e.offsetY}px`;
      tooltip.style.left = `${e.offsetX}px`;
    });
    item.addEventListener("mouseleave", () => {
      tooltip.style.display = "none";
    });
  });

  return (
    <div className="marquee-container">
      <Marquee gradient={false} speed={40} direction="up">
        <div
          className="marquee-item"
          onClick={() => handleClick(0)}
          onMouseEnter={handleMouseEnter}
          onMouseMove={handleMouseMove}
          onMouseLeave={handleMouseLeave}
        >
          <div className="marquee-item-box">
            <img src={img1} alt="example" />
            <span>
              Lorem ipsum dolor sit amet, consectetur adipiscing elit.
            </span>
            {tooltipVisible && (
              <div
                className="tooltip"
                style={{ left: tooltipX, top: tooltipY }}
              >
                <span className="tooltip-text">Click to learn more</span>
                <img
                  className="tooltip-arrow"
                  src="./images/arrow.png"
                  alt="Tooltip arrow"
                />
              </div>
            )}
          </div>
        </div>
        <div
          className="marquee-item"
          onClick={() => handleClick(1)}
          onMouseEnter={handleMouseEnter}
          onMouseMove={handleMouseMove}
          onMouseLeave={handleMouseLeave}
        >
          <div className="marquee-item-box">
            <img src={img2} alt="example" />
            <span>
              Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.
            </span>
            {tooltipVisible && (
              <div
                className="tooltip"
                style={{ left: tooltipX, top: tooltipY }}
              >
                <span className="tooltip-text">Click to learn more</span>
                <img
                  className="tooltip-arrow"
                  src="./images/arrow.png"
                  alt="Tooltip arrow"
                />
              </div>
            )}
          </div>
        </div>
        {/* <div
          className="marquee-item"
          onClick={() => handleClick(1)}
          onMouseEnter={handleMouseEnter}
          onMouseLeave={handleMouseLeave}
        >
          <div className="marquee-item-box">
            <img src={img3} alt="example" />
            <span>
              Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.
            </span>
            {tooltip.show && (
              <div
                className="tooltip"
                style={{ left: tooltip.x + 20, top: tooltip.y - 30 }}
              >
                <span className="tooltip-text">Click to learn more</span>
                <img
                  className="tooltip-arrow"
                  src="./images/arrow.png"
                  alt="Tooltip arrow"
                />
              </div>
            )}
          </div>
        </div> */}
      </Marquee>
    </div>
  );
}

export default MarqueeExample;
